55	const PROCESSING_FEE = 5;
56	const BLOCK_SIZE = 3;
57	const RUNE_BLOCK_PRICE = 60;
58	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
59	  sword: 100,
60	  amulet: 60,
61	  staff: 80,
62	  potion: 40,
63	  rune: 25,
64	};
65	
66	const basePremium = (item: Item): number =>
67	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
68	
69	const isRuneBlock = (items: Item[]): boolean =>
70	  items.length === BLOCK_SIZE && items.every((it) => it.type === "rune");
71	
72	const sumBasePremiums = (items: Item[]): number =>
73	  items.reduce((sum, item) => sum + basePremium(item), 0);
74	
75	const componentsTotal = (items: Item[]): number =>
76	  isRuneBlock(items) ? RUNE_BLOCK_PRICE : sumBasePremiums(items);
77	
78	const quotePremium = (items: Item[]): number =>
79	  componentsTotal(items) + PROCESSING_FEE;
80	
81	export const processScenario = (scenario: Scenario): ScenarioOutput => {
82	  const step = scenario.steps[0] as QuoteStep;
83	  return { results: [{ premium: quotePremium(step.items) }] };
84	};
